SELECT ir.INSPECT_ID AS inspectId, ir.PLANT_CD AS plantCd, ir.INSPECT_NO AS inspectNo, ir.INSPECT_TYPE AS inspectType, ir.INSPECT_DT AS inspectDt, ir.ITEM_CD AS itemCd, ir.LOT_NO AS lotNo, ir.INSPECT_QTY AS inspectQty, ir.SAMPLE_QTY AS sampleQty, ir.PASS_QTY AS passQty, ir.FAIL_QTY AS failQty, ir.INSPECTOR_ID AS inspectorId, ir.WO_ID AS woId, ir.RESULT_ID AS resultId, ir.RECEIVE_ID AS receiveId, ir.VENDOR_CD AS vendorCd, ir.JUDGE_RESULT AS judgeResult, ir.JUDGE_USER_ID AS judgeUserId, ir.JUDGE_DTM AS judgeDtm, ir.PROCESS_CD AS processCd, ir.INSPECT_RMK AS inspectRmk, ir.REG_USER_ID AS regUserId, ir.REG_DTM AS regDtm FROM QC_INSPECT_RESULT ir WHERE 1 = 1
AND ir.PLANT_CD = #{plantCd}
AND ir.ITEM_CD = #{itemCd}
AND ir.INSPECT_DT >= #{inspectFromDt}
AND ir.INSPECT_DT <= #{inspectToDt}
ORDER BY ir.INSPECT_DT DESC, ir.INSPECT_ID DESC

SELECT ir.INSPECT_ID AS inspectId, ir.PLANT_CD AS plantCd, ir.INSPECT_NO AS inspectNo, ir.INSPECT_TYPE AS inspectType, ir.INSPECT_DT AS inspectDt, ir.ITEM_CD AS itemCd, ir.LOT_NO AS lotNo, ir.INSPECT_QTY AS inspectQty, ir.SAMPLE_QTY AS sampleQty, ir.PASS_QTY AS passQty, ir.FAIL_QTY AS failQty, ir.INSPECTOR_ID AS inspectorId, ir.WO_ID AS woId, ir.RESULT_ID AS resultId, ir.RECEIVE_ID AS receiveId, ir.VENDOR_CD AS vendorCd, ir.JUDGE_RESULT AS judgeResult, ir.JUDGE_USER_ID AS judgeUserId, ir.JUDGE_DTM AS judgeDtm, ir.PROCESS_CD AS processCd, ir.INSPECT_RMK AS inspectRmk, ir.REG_USER_ID AS regUserId, ir.REG_DTM AS regDtm FROM QC_INSPECT_RESULT ir WHERE 1 = 1
AND ir.PLANT_CD = #{plantCd}
AND ir.ITEM_CD = #{itemCd}
AND ir.INSPECT_DT >= #{inspectFromDt}
AND ir.INSPECT_DT <= #{inspectToDt}
ORDER BY ir.INSPECT_DT DESC, ir.INSPECT_ID DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM QC_INSPECT_RESULT ir
WHERE 1 = 1

    AND ir.PLANT_CD = #{plantCd}


    AND ir.ITEM_CD = #{itemCd}


    AND ir.INSPECT_DT >= #{inspectFromDt}


    AND ir.INSPECT_DT <= #{inspectToDt}

